import React, { useEffect, useRef, useState } from "react";
import "./EditProfile.css";

// Same base inference you used elsewhere
const API_BASE = (process.env.REACT_APP_API_BASE || "http://localhost:5000/api")
  .replace(/\/+$/, "");

function buildHeaders(extra = {}) {
  const token = localStorage.getItem("token");
  return {
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
    ...extra,
  };
}

export default function ProfilePanel() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [msg, setMsg] = useState("");

  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    addressLine1: "",
    addressLine2: "",
    city: "",
    state: "",
    zip: "",
    country: "",
    lat: "",
    lng: "",
    avatarUrl: "",
  });

  // Avatar upload preview
  const [avatarPreview, setAvatarPreview] = useState("");
  const fileRef = useRef(null);

  // Load current profile
  useEffect(() => {
    let ok = true;
    (async () => {
      setLoading(true);
      setError("");
      try {
        const res = await fetch(`${API_BASE}/auth/me`, {
          headers: buildHeaders(),
          credentials: "include",
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();

        // Map defensively
        const u = data?.user || data || {};
        if (ok) {
          setForm((prev) => ({
            ...prev,
            name: u.name || "",
            email: u.email || "",
            phone: u.phone || "",
            addressLine1: u.address?.line1 || "",
            addressLine2: u.address?.line2 || "",
            city: u.address?.city || "",
            state: u.address?.state || "",
            zip: u.address?.zip || "",
            country: u.address?.country || "",
            lat: u.location?.lat ?? "",
            lng: u.location?.lng ?? "",
            avatarUrl: u.avatarUrl || "",
          }));
          setAvatarPreview(u.avatarUrl || "");
        }
      } catch (e) {
        if (ok) setError("Failed to load profile.");
        console.error(e);
      } finally {
        if (ok) setLoading(false);
      }
    })();
    return () => {
      ok = false;
    };
  }, []);

  // Handle simple field changes
  const setVal = (key, value) => setForm((f) => ({ ...f, [key]: value }));

  // Geolocate
  const grabLocation = () => {
    setMsg("");
    setError("");
    if (!navigator.geolocation) {
      setError("Geolocation not supported.");
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const { latitude, longitude } = pos.coords;
        setVal("lat", latitude.toFixed(6));
        setVal("lng", longitude.toFixed(6));
        setMsg("Location captured.");
      },
      (err) => {
        console.error(err);
        setError("Could not get your current location.");
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  // Save profile
  const onSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    setMsg("");
    setError("");

    // Minimal client validation
    if (!form.name.trim()) {
      setError("Please enter your name.");
      setSaving(false);
      return;
    }
    if (!form.email.trim()) {
      setError("Email is required.");
      setSaving(false);
      return;
    }

    // Shape body the backend likely expects
    const payload = {
      name: form.name.trim(),
      phone: form.phone.trim(),
      address: {
        line1: form.addressLine1.trim(),
        line2: form.addressLine2.trim(),
        city: form.city.trim(),
        state: form.state.trim(),
        zip: form.zip.trim(),
        country: form.country.trim(),
      },
      location:
        form.lat && form.lng
          ? { lat: Number(form.lat), lng: Number(form.lng) }
          : undefined,
    };

    try {
      const res = await fetch(`${API_BASE}/auth/profile`, {
        method: "PUT",
        headers: buildHeaders(),
        body: JSON.stringify(payload),
        credentials: "include",
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data?.message || `HTTP ${res.status}`);
      }
      setMsg("Profile saved ✔");
    } catch (e) {
      console.error(e);
      setError(e.message || "Failed to save profile.");
    } finally {
      setSaving(false);
    }
  };

  // Upload avatar (multipart)
  const onPickAvatar = async (ev) => {
    const file = ev.target.files?.[0];
    if (!file) return;

    // preview
    const url = URL.createObjectURL(file);
    setAvatarPreview(url);

    const formData = new FormData();
    formData.append("avatar", file);

    try {
      setMsg("");
      setError("");
      const res = await fetch(`${API_BASE}/auth/avatar`, {
        method: "POST",
        headers: buildHeaders({ "Content-Type": undefined }), // Let browser set boundary
        body: formData,
        credentials: "include",
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data?.message || `HTTP ${res.status}`);
      }
      const data = await res.json();
      setVal("avatarUrl", data?.avatarUrl || "");
      setMsg("Photo updated ✔");
    } catch (e) {
      console.error(e);
      setError(e.message || "Failed to upload photo.");
      // rollback preview if failed
      setAvatarPreview(form.avatarUrl || "");
    }
  };

  if (loading) return <div className="profile-wrap"><div className="card loading">Loading…</div></div>;

  return (
    <div className="profile-wrap">
      <div className="card">
        <div className="top">
          <div className="avatar">
            <img
              src={
                avatarPreview ||
                "https://ui-avatars.com/api/?name=" +
                  encodeURIComponent(form.name || "User")
              }
              alt="avatar"
            />
            <button
              type="button"
              className="btn outline small"
              onClick={() => fileRef.current?.click()}
            >
              Change Photo
            </button>
            <input
              ref={fileRef}
              type="file"
              accept="image/*"
              hidden
              onChange={onPickAvatar}
            />
          </div>

          <div className="identity">
            <div className="title">{form.name || "Your Name"}</div>
            <div className="subtitle">{form.email}</div>
          </div>
        </div>

        <form className="form" onSubmit={onSave}>
          <div className="grid">
            <div className="field">
              <label>Name</label>
              <input
                value={form.name}
                onChange={(e) => setVal("name", e.target.value)}
                placeholder="Full name"
              />
            </div>

            <div className="field">
              <label>Email</label>
              <input value={form.email} disabled />
              <small className="muted">Email can’t be changed</small>
            </div>

            <div className="field">
              <label>Phone</label>
              <input
                value={form.phone}
                onChange={(e) => setVal("phone", e.target.value)}
                placeholder="Phone number"
                inputMode="tel"
              />
            </div>

            <div className="field">
              <label>Address line 1</label>
              <input
                value={form.addressLine1}
                onChange={(e) => setVal("addressLine1", e.target.value)}
                placeholder="House / Street"
              />
            </div>

            <div className="field">
              <label>Address line 2</label>
              <input
                value={form.addressLine2}
                onChange={(e) => setVal("addressLine2", e.target.value)}
                placeholder="Area / Landmark (optional)"
              />
            </div>

            <div className="field">
              <label>City</label>
              <input
                value={form.city}
                onChange={(e) => setVal("city", e.target.value)}
                placeholder="City"
              />
            </div>

            <div className="field">
              <label>State</label>
              <input
                value={form.state}
                onChange={(e) => setVal("state", e.target.value)}
                placeholder="State"
              />
            </div>

            <div className="field">
              <label>ZIP / PIN</label>
              <input
                value={form.zip}
                onChange={(e) => setVal("zip", e.target.value)}
                placeholder="Postal code"
                inputMode="numeric"
              />
            </div>

            <div className="field">
              <label>Country</label>
              <input
                value={form.country}
                onChange={(e) => setVal("country", e.target.value)}
                placeholder="Country"
              />
            </div>
          </div>

          <div className="loc-row">
            <div className="field sm">
              <label>Latitude</label>
              <input
                value={form.lat}
                onChange={(e) => setVal("lat", e.target.value)}
                placeholder="e.g. 17.3850"
              />
            </div>
            <div className="field sm">
              <label>Longitude</label>
              <input
                value={form.lng}
                onChange={(e) => setVal("lng", e.target.value)}
                placeholder="e.g. 78.4867"
              />
            </div>
            <button
              type="button"
              className="btn ghost"
              onClick={grabLocation}
              title="Use current location"
            >
              Use Current Location
            </button>
          </div>

          {error && <div className="alert error">{error}</div>}
          {msg && <div className="alert ok">{msg}</div>}

          <div className="actions">
            <button type="submit" className="btn primary" disabled={saving}>
              {saving ? "Saving…" : "Save Changes"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
